'use client';

import Link from 'next/link';
import { motion } from 'framer-motion';
import { Search, TrendingUp } from 'lucide-react';
import { mockArticles } from '@/data/articles';
import { mockTopics } from '@/data/topics';
import { formatNumber } from '@/lib/utils';
import { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function RightPanel() {
  const [searchQuery, setSearchQuery] = useState('');
  const router = useRouter();

  const trending = [...mockArticles]
    .sort((a, b) => (b.likesCount + b.commentsCount) - (a.likesCount + a.commentsCount))
    .slice(0, 5);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      router.push(`/?search=${encodeURIComponent(searchQuery.trim())}`);
    }
  };

  return (
    <aside className="w-[320px] shrink-0 max-xl:hidden">
      <div className="sticky top-[49px] h-[calc(100vh-49px)] overflow-y-auto py-4 pl-2 pr-4 space-y-4">
        {/* Search */}
        <form onSubmit={handleSearch} className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-secondary)' }} />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Tìm kiếm tin tức..."
            className="w-full pl-10 pr-4 py-2.5 rounded-2xl border text-sm focus:outline-none"
            style={{ background: 'var(--bg-glass-strong)', backdropFilter: 'var(--glass-blur)', borderColor: 'var(--border-glass)', color: 'var(--text-primary)' }}
            onFocus={(e) => (e.target.style.borderColor = '#F97316')}
            onBlur={(e) => (e.target.style.borderColor = 'var(--border-glass)')}
          />
        </form>

        {/* Trending */}
        <div className="rounded-2xl overflow-hidden"
          style={{ background: 'var(--bg-glass-strong)', border: '1px solid var(--border-glass)', boxShadow: 'var(--shadow-glass)', backdropFilter: 'var(--glass-blur)' }}
        >
          <div className="px-4 py-3 flex items-center gap-2">
            <TrendingUp className="w-5 h-5" style={{ color: '#F97316' }} />
            <h2 className="text-lg font-bold" style={{ color: 'var(--text-primary)' }}>Xu hướng</h2>
          </div>
          {trending.map((article, i) => (
            <Link key={article.id} href={`/article/${article.id}`}>
              <motion.div
                whileHover={{ backgroundColor: 'var(--bg-hover)' }}
                className="px-4 py-3 border-t cursor-pointer"
                style={{ borderColor: 'var(--border-primary)' }}
              >
                <div className="flex items-start justify-between gap-2">
                  <div className="min-w-0 flex-1">
                    <p className="text-xs mb-0.5" style={{ color: 'var(--text-secondary)' }}>
                      {article.topic.icon} {article.topic.name} · Xu hướng
                    </p>
                    <p className="text-sm font-semibold leading-tight line-clamp-2" style={{ color: 'var(--text-primary)' }}>
                      {article.title}
                    </p>
                    <p className="text-xs mt-1" style={{ color: 'var(--text-secondary)' }}>
                      {formatNumber(article.likesCount + article.commentsCount)} lượt tương tác
                    </p>
                  </div>
                  <span className="text-lg font-bold shrink-0" style={{ color: 'var(--border-light)' }}>
                    {i + 1}
                  </span>
                </div>
              </motion.div>
            </Link>
          ))}
          <Link href="/trending">
            <div className="px-4 py-3 border-t text-sm font-medium" style={{ borderColor: 'var(--border-primary)', color: '#F97316' }}>
              Xem thêm
            </div>
          </Link>
        </div>

        {/* Topics */}
        <div className="rounded-2xl overflow-hidden"
          style={{ background: 'var(--bg-glass-strong)', border: '1px solid var(--border-glass)', boxShadow: 'var(--shadow-glass)', backdropFilter: 'var(--glass-blur)' }}
        >
          <div className="px-4 py-3">
            <h2 className="text-lg font-bold" style={{ color: 'var(--text-primary)' }}>Chủ đề</h2>
          </div>
          <div className="px-4 pb-4 flex flex-wrap gap-2">
            {mockTopics.map((topic) => (
              <Link key={topic.slug} href={`/topic/${topic.slug}`}>
                <motion.span
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                  className="inline-flex items-center gap-1 px-3 py-1.5 rounded-full text-sm font-medium cursor-pointer border"
                  style={{
                    borderColor: 'var(--border-glass)',
                    color: 'var(--text-primary)',
                    background: 'var(--bg-glass)',
                  }}
                >
                  {topic.icon} {topic.name}
                </motion.span>
              </Link>
            ))}
          </div>
        </div>

        {/* Footer */}
        <div className="px-2">
          <p className="text-xs" style={{ color: 'var(--text-tertiary)' }}>
            © 2024 NewsX · Nền tảng tin tức thế hệ mới
          </p>
        </div>
      </div>
    </aside>
  );
}
